<script setup lang="ts">
import { computed, onMounted, onUnmounted, ref } from "vue";
const showGuide = ref(false);
const baseUrl = import.meta.env.BASE_URL;
import { App, Frame, Leafer } from "leafer-ui";
import "leafer-editor";
import {
  htmlTextManage,
  setLicense,
  setHTMLText,
  HtmlText,
} from "@chenyomi/leafer-htmltext-edit";

let leafer: any, frame: Frame;
let selectionSyncTimer: number | undefined;
const externalFontStyle = `<style>@font-face {font-family: 'YouSheBiaoTiHei-2';src: url(data:font/woff2;base64,) format('woff2');}</style>`;
const externalHtmlText = '<div style="width: 980px;height:294px;overflow-wrap:break-word;word-break:break-all;display:flex;flex-direction:column;justify-content:flex-start;"><p class="ql-align-center" style="letter-spacing: 0px; font-size: 70px; line-height: 1.5; text-shadow: none; font-family: YouSheBiaoTiHei-2; paint-order: unset; -webkit-text-stroke: unset;"><span style="-webkit-text-stroke: 6px rgb(0, 66, 104); font-family: YouSheBiaoTiHei-2; text-shadow: none; color: rgb(253, 225, 5);">外部HTML恢复加载，无需元数据，支持插件源生的html内容</span></p></div>';

onMounted(async () => {
  // 1. 设置 License（必须在 init 之前）
  // "2028-08-13"到期 仅仅支持localhost调试
  const licenseKey = ""
  // const licenseKey =
  //   "";
  const success = await setLicense(licenseKey);
  if (!success) {
    console.error("License validation failed");
  }
  leafer = new App({
    view: "leafer-view",
    fill: "#1a1a2e",
    editor: {},
  });
  // 2. 初始化
  htmlTextManage.init(leafer);
  frame = new Frame({
    width: window.innerWidth * 0.7,
    height: window.innerHeight * 0.7,
    x: window.innerWidth * 0.15,
    y: window.innerHeight * 0.15,
    fill: "#fff",
    overflow: "show",
  });
  leafer.tree.add(frame);
  addExternalHtmlTextCase();
  addInitialHtmlTextContent();
  syncLockRatioState();
  selectionSyncTimer = window.setInterval(syncLockRatioState, 120);
});

onUnmounted(() => {
  if (selectionSyncTimer) window.clearInterval(selectionSyncTimer);
});
const addExternalHtmlTextCase = () => {
  if (!frame) return;
  // 直接使用字符串创建文本框，内容为外部复制的文本（包含样式）
  const text = new HtmlText({
    x: window.innerWidth * 0.01,
    y: window.innerHeight * 0.32,
    editable: true,
    draggable: true,
    text: externalFontStyle + externalHtmlText,
  });
  frame.add(text as any);
};

const addInitialHtmlTextContent = () => {
  if (!frame) return;
  // 元数据加载方式创建文本框，内容为 Hello World!
  const text = new HtmlText({
    x: window.innerWidth * 0.28 + Math.random() * 40,
    y: window.innerHeight * 0.24 + Math.random() * 30,
    editable: true,
    draggable: true,
    fontSize: 28,
    lineHeight: 1.5,
    letterSpacing: 0,
    alignContent: 'start',
    color: '#e74c3c',
    content: 'Hello World!',
  } as any);
  frame.add(text as any);
};

const fontFamily = '"Dancing Script", cursive';
const fontBase64 =
  "data:font/woff2;charset=utf-8;base64,";
const changeFontFamily = () => {
  setHTMLText("font", fontFamily, fontBase64);
};
const reload = () => {
  window.location.reload();
};
const print = () => {
  const canvas = htmlTextManage.getCanvas();
  if (!canvas) return;
  canvas.editor.list.forEach((item: any) => {
    const copy = item.clone();
    copy.x += 10;
    copy.y += 10;
    frame.add(copy);
  });
};

// ---- 锁定比例 ----
const lockRatioEnabled = ref(false);
const selectedElements = ref<any[]>([]);
const hasLockRatioSelection = computed(() => selectedElements.value.length > 0);
const getSelectedElements = () => {
  const canvas = htmlTextManage.getCanvas();
  return [...(canvas?.editor?.list || [])];
};
const syncLockRatioState = () => {
  const list = getSelectedElements();
  const nextLockRatioEnabled = list.length > 0 && list.every((item: any) => item.lockRatio === true);
  const sameSelection =
    list.length === selectedElements.value.length &&
    list.every((item: any, index: number) => item === selectedElements.value[index]);

  if (sameSelection && lockRatioEnabled.value === nextLockRatioEnabled) return;

  selectedElements.value = list;
  lockRatioEnabled.value = nextLockRatioEnabled;
};
const toggleLockRatio = () => {
  const list = getSelectedElements();
  if (list.length === 0) return;

  const nextLockRatioEnabled = !lockRatioEnabled.value;
  list.forEach((item: any) => {
    item.lockRatio = nextLockRatioEnabled;
  });
  syncLockRatioState();
};

// ---- 画布缩放 ----
const zoomIn = () => { htmlTextManage.getCanvas()?.zoom('in'); };
const zoomOut = () => { htmlTextManage.getCanvas()?.zoom('out'); };
const zoomFit = () => { htmlTextManage.getCanvas()?.zoom('fit'); };
const zoomReset = () => { htmlTextManage.getCanvas()?.zoom(1); };

// ---- 元素旋转 ----
const rotateElement = (delta: number) => {
  htmlTextManage.dateEdit((leaf: any) => {
    leaf.rotation = ((leaf.rotation || 0) + delta + 360) % 360;
  });
};
const resetRotation = () => {
  htmlTextManage.dateEdit((leaf: any) => { leaf.rotation = 0; });
};

// ---- 元素缩放 ----
const scaleElement = (val: number) => {
  htmlTextManage.dateEdit((leaf: any) => {
    leaf.scaleX = val;
    leaf.scaleY = val;
  });
};

// ---- 弧形文字 ----
const setArcText = () => {
  htmlTextManage.dateEdit((e: any) => {
    const rawText = htmlTextManage.getQuill()?.getText()?.replace(/\n$/, '')?.trim() || '弧形文字示例';
    const id = 'arc' + Date.now();
    e.text = `<svg xmlns="http://www.w3.org/2000/svg" width="320" height="130" viewBox="0 0 320 130"><defs><path id="${id}" d="M10,110 A155,155 0 0,1 310,110"/></defs><text font-size="26" font-weight="bold" fill="#333"><textPath href="#${id}">${rawText}</textPath></text></svg>`;
  }, 1);
};
const resetArcText = () => {
  htmlTextManage.dateEdit((e: any) => {
    e.text = e.text?.replace(/<svg[\s\S]*?<\/svg>/gi, '') || '';
  }, 1);
};

// ---- 底部面板操作 ----
const addText = () => {
  const canvas = htmlTextManage.getCanvas();
  if (!canvas) return;
  const text = new HtmlText({
    editOuter: 'TextEditTool',
    name: 'Text',
    x: window.innerWidth * 0.35 + Math.random() * 60,
    y: window.innerHeight * 0.35 + Math.random() * 40,
    editable: true,
    draggable: true,
    fontSize: 24,
    lineHeight: 1.5,
    letterSpacing: 0,
    alignContent: 'start',
  });
  frame.add(text as any);
};

const addTextWithInitialFont = () => {
  const canvas = htmlTextManage.getCanvas();
  if (!canvas) return;
  const text = new HtmlText({
    editOuter: 'TextEditTool',
    name: 'InitialFontText',
    x: window.innerWidth * 0.35 + Math.random() * 60,
    y: window.innerHeight * 0.45 + Math.random() * 40,
    editable: true,
    draggable: true,
    fontFamily,
    fontBase64,
    fontSize: 32,
    lineHeight: 1.5,
    letterSpacing: 0,
    alignContent: 'start',
    color: '#8e44ad',
    content: 'Initial Font Text',
  } as any);
  frame.add(text as any);
};

const deleteSelected = () => {
  const canvas = htmlTextManage.getCanvas();
  if (!canvas) return;
  const list = [...(canvas.editor?.list || [])];
  if (list.length === 0) return;
  list.forEach((item: any) => item.remove());
  canvas.editor.cancel();
  syncLockRatioState();
};

const duplicateSelected = () => { print(); };

const selectAll = () => {
  const canvas = htmlTextManage.getCanvas();
  if (!canvas) return;
  const items = frame.children || [];
  if (items.length) canvas.editor.select(items as any);
  syncLockRatioState();
};

const cancelSelect = () => {
  htmlTextManage.getCanvas()?.editor?.cancel();
  syncLockRatioState();
};
</script>

<template>
  <div id="leafer-view"></div>

  <!-- 顶部介绍栏 -->
  <div class="intro-bar">
    <div class="intro-left">
      <img class="brand-logo" :src="`${baseUrl}chenyomi-logo.svg`" alt="chenyomi" />
      <span class="plugin-badge">Plugin</span>
      <span class="plugin-name">@chenyomi/leafer-htmltext-edit</span>
      <span class="plugin-desc">基于 Leafer UI + Quill 2.0 的富文本编辑器插件</span>
    </div>
    <div class="intro-right">
      <span class="tip-text">💡 双击文本框进入编辑，选中文字后点击按钮应用样式</span>
      <a
        class="guide-toggle-btn docs-link-btn"
        href="https://chenyomi.github.io/leafer-htmltext-edit-website/docs"
        target="_blank"
        rel="noopener noreferrer"
      >
        文档 ↗
      </a>
      <button class="guide-toggle-btn" @click="showGuide = !showGuide">
        {{ showGuide ? '收起指南 ▲' : '操作指南 ▼' }}
      </button>
    </div>
  </div>

  <!-- 操作指南面板 -->
  <div class="guide-panel" v-show="showGuide">
    <div class="guide-inner">
      <div class="guide-section">
        <h4>🚀 快速开始</h4>
        <ul>
          <li>双击画布中的<strong>文本框</strong>进入内联编辑模式</li>
          <li>单击文本框可选中，拖拽移动位置，缩放改变大小</li>
          <li>编辑模式下选中文字后，点击左/右侧工具栏按钮应用样式</li>
          <li>未选中文字时点击按钮，对整个文本块应用样式</li>
        </ul>
      </div>
      <div class="guide-section">
        <h4>✨ 功能一览</h4>
        <ul>
          <li><strong>字体样式</strong> — 加粗 / 斜体 / 下划线 / 删除线 / 大小写转换</li>
          <li><strong>上下标</strong> — 上标 X² 和下标 H₂O</li>
          <li><strong>水平对齐</strong> — 左对齐 / 居中 / 右对齐 / 两端对齐 / 分散对齐</li>
          <li><strong>垂直对齐</strong> — 顶部 / 垂直居中 / 底部</li>
          <li><strong>列表</strong> — 有序列表（1. 2. 3.）和无序列表（• • •）</li>
          <li><strong>文字颜色</strong> — 改变选中文字的颜色</li>
          <li><strong>行高 / 字间距</strong> — 精细控制文字行距和字符间距</li>
          <li><strong>文字阴影</strong> — 为文字添加投影特效</li>
          <li><strong>轮廓描边</strong> — 为文字添加描边效果</li>
          <li><strong>自定义字体</strong> — 传入 Base64 字体数据切换字体</li>
          <li><strong>画布缩放</strong> — 放大 / 缩小 / 适合屏幕 / 1:1 原始大小</li>
          <li><strong>锁定比例</strong> — 选中元素后锁定，拖拽缩放时保持宽高比</li>
          <li><strong>元素缩放</strong> — 对选中元素按比例缩放 50%~200%</li>
          <li><strong>旋转</strong> — 对选中元素旋转 ±15° / +90° 或归零</li>
          <li><strong>弧形文字</strong> — 将文字沿弧形路径排列（SVG TextPath）</li>
        </ul>
      </div>
      <div class="guide-section">
        <h4>🔧 核心 API</h4>
        <ul>
          <li><code>await setLicense(key)</code> — 激活授权（init 之前调用）</li>
          <li><code>htmlTextManage.init(app)</code> — 初始化插件，绑定 Leafer App</li>
          <li><code>setHTMLText(key, value?)</code> — 设置文本属性（选中状态下生效）</li>
          <li><code>htmlTextManage.getQuill()</code> — 获取 Quill 实例，可监听事件</li>
          <li><code>htmlTextManage.getCanvas()</code> — 获取 Leafer App 实例</li>
          <li><code>htmlTextManage.dateEdit(cb)</code> — 批量编辑多选对象</li>
          <li><code>new HtmlText({...})</code> — 创建富文本节点</li>
        </ul>
      </div>
      <div class="guide-section">
        <h4>📦 安装</h4>
        <ul>
          <li><code>pnpm add @chenyomi/leafer-htmltext-edit</code></li>
          <li>Peer: leafer-ui · @leafer-ui/core · @leafer-in/editor · @leafer-in/html · quill</li>
        </ul>
      </div>
    </div>
  </div>

  <!-- 左侧工具栏 - 文字格式 -->
  <div class="toolbar left-toolbar">
    <div class="toolbar-title">文字格式</div>

    <div class="toolbar-group">
      <div class="group-label">字体样式</div>
      <button @click="setHTMLText('bold')"><b>B</b> 加粗</button>
      <button @click="setHTMLText('italic')"><i>I</i> 斜体</button>
      <button @click="setHTMLText('underline')"><u>U</u> 下划线</button>
      <button @click="setHTMLText('strike')"><s>S</s> 删除线</button>
      <button @click="setHTMLText('textCase')">Aa 大小写</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">上下标</div>
      <button @click="setHTMLText('script', 'super')">X² 上标</button>
      <button @click="setHTMLText('script', 'sub')">X₂ 下标</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">水平对齐</div>
      <button @click="setHTMLText('align', false)">≡ 左对齐</button>
      <button @click="setHTMLText('align', 'center')">≡ 居中</button>
      <button @click="setHTMLText('align', 'right')">≡ 右对齐</button>
      <button @click="setHTMLText('align', 'justify')">≡ 两端对齐</button>
      <button @click="setHTMLText('align', 'distribute')">≡ 分散对齐</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">垂直对齐</div>
      <button @click="setHTMLText('alignContent', 'start')">↑ 顶部</button>
      <button @click="setHTMLText('alignContent', 'center')">⊙ 居中</button>
      <button @click="setHTMLText('alignContent', 'end')">↓ 底部</button>
    </div>

  </div>

  <!-- 顶部操作面板（文本 + 选择 + 画布缩放） -->
  <div class="bottom-panel top-action-panel">
    <div class="bottom-panel-group">
      <div class="bottom-group-label">文本</div>
      <button class="bottom-btn primary" @click="addText">＋ 添加文本</button>
      <button class="bottom-btn primary" @click="addInitialHtmlTextContent">＋ 初始HTML内容</button>
      <button class="bottom-btn primary" @click="addExternalHtmlTextCase">＋ 外部HTML恢复</button>
      <button class="bottom-btn primary" @click="addTextWithInitialFont">＋ 初始字体文本</button>
      <button class="bottom-btn danger" @click="deleteSelected">✕ 删除选中</button>
    </div>
    <div class="bottom-divider"></div>
    <div class="bottom-panel-group">
      <div class="bottom-group-label">选择</div>
      <button class="bottom-btn" @click="selectAll">⊞ 全选</button>
      <button class="bottom-btn" @click="cancelSelect">⊟ 取消选中</button>
    </div>
    <div class="bottom-divider"></div>
    <div class="bottom-panel-group">
      <div class="bottom-group-label">画布缩放</div>
      <button class="bottom-btn" @click="zoomIn">＋ 放大</button>
      <button class="bottom-btn" @click="zoomOut">− 缩小</button>
      <button class="bottom-btn" @click="zoomFit">⊡ 适合</button>
      <button class="bottom-btn" @click="zoomReset">1:1</button>
    </div>
  </div>

  <!-- 底部操作面板（旋转 + 缩放 + 其他） -->
  <div class="bottom-panel bottom-action-panel">
    <div class="bottom-panel-group">
      <div class="bottom-group-label">旋转</div>
      <button class="bottom-btn" @click="rotateElement(-15)">↺ −15°</button>
      <button class="bottom-btn" @click="rotateElement(15)">↻ +15°</button>
      <button class="bottom-btn" @click="rotateElement(90)">↻ +90°</button>
      <button class="bottom-btn" @click="resetRotation">⊙ 归零</button>
    </div>
    <div class="bottom-divider"></div>
    <div class="bottom-panel-group">
      <div class="bottom-group-label">缩放</div>
      <button class="bottom-btn" @click="scaleElement(0.5)">50%</button>
      <button class="bottom-btn" @click="scaleElement(1)">100%</button>
      <button class="bottom-btn" @click="scaleElement(1.5)">150%</button>
      <button class="bottom-btn" @click="scaleElement(2)">200%</button>
    </div>
    <div class="bottom-divider"></div>
    <div class="bottom-panel-group">
      <div class="bottom-group-label">其他</div>
      <button class="bottom-btn" @click="duplicateSelected">⧉ 复制选中</button>
      <button
        v-if="hasLockRatioSelection"
        class="bottom-btn"
        :class="{ 'btn-active': lockRatioEnabled }"
        @click="toggleLockRatio"
      >
        {{ lockRatioEnabled ? '🔒 已锁定' : '🔓 锁定比例' }}
      </button>
      <button class="bottom-btn danger" @click="reload">↺ 重置页面</button>
    </div>
  </div>

  <!-- 右侧工具栏 - 样式效果 -->
  <div class="toolbar right-toolbar">
    <div class="toolbar-title">样式效果</div>

    <div class="toolbar-group">
      <div class="group-label">列表</div>
      <button @click="setHTMLText('list', 'ordered')">1. 有序列表</button>
      <button @click="setHTMLText('list', 'bullet')">• 无序列表</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">文字颜色</div>
      <button class="color-dot green" @click="setHTMLText('color', '#3CB72C')">● 绿色 #3CB72C</button>
      <button class="color-dot black" @click="setHTMLText('color', '#000000')">● 黑色 #000000</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">行高</div>
      <button @click="setHTMLText('lineHeight', 1.5)">行高 1.5×</button>
      <button @click="setHTMLText('lineHeight', 3)">行高 3.0×</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">字间距</div>
      <button @click="setHTMLText('letterSpacing', 0)">字间距 0</button>
      <button @click="setHTMLText('letterSpacing', 3)">字间距 3px</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">内边距</div>
      <button @click="setHTMLText('padding', 20)">Padding 20</button>
      <button @click="setHTMLText('padding', [5, 10, 15, 20])">Padding [5,10,15,20]</button>
      <button @click="setHTMLText('padding', 0)">Padding 0</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">文字阴影</div>
      <button @click="setHTMLText('textShadow', '3px 3px 3px rgba(0,0,0,0.5)')">黑色阴影</button>
      <button @click="setHTMLText('textShadow', '2px 2px 0px red')">红色阴影</button>
      <button @click="setHTMLText('textShadow', undefined)">移除阴影</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">轮廓描边</div>
      <button @click="setHTMLText('textStroke', '4px yellow')">黄色描边</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">字体 & 字号</div>
      <button @click="changeFontFamily">Dancing Script 字体</button>
      <button @click="setHTMLText('fontSize', 100)">大字号 100px</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">画布缩放</div>
      <button @click="zoomIn">🔍+ 放大</button>
      <button @click="zoomOut">🔍− 缩小</button>
      <button @click="zoomFit">⊡ 适合屏幕</button>
      <button @click="zoomReset">1:1 原始大小</button>
    </div>

    <div v-if="hasLockRatioSelection" class="toolbar-group">
      <div class="group-label">锁定比例</div>
      <button :class="{ 'btn-active': lockRatioEnabled }" @click="toggleLockRatio">
        {{ lockRatioEnabled ? '🔒 已锁定' : '🔓 锁定比例' }}
      </button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">元素缩放</div>
      <button @click="scaleElement(0.5)">缩小 50%</button>
      <button @click="scaleElement(1)">还原 100%</button>
      <button @click="scaleElement(1.5)">放大 150%</button>
      <button @click="scaleElement(2)">放大 200%</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">旋转</div>
      <button @click="rotateElement(-15)">↺ −15°</button>
      <button @click="rotateElement(15)">↻ +15°</button>
      <button @click="rotateElement(90)">↻ +90°</button>
      <button @click="resetRotation">⊙ 归零</button>
    </div>

    <div class="toolbar-group">
      <div class="group-label">弧形文字</div>
      <button @click="setArcText">∿ 应用弧形</button>
      <button @click="resetArcText">✕ 还原文字</button>
    </div>
  </div>
</template>

